-- Migración 054: campos extendidos para jugadores + plantel Asociación Buin 2026
-- Agrega columnas nuevas a jugadores (telefono, categoria y entrenamientos_por_semana ya existen)
ALTER TABLE jugadores
  ADD COLUMN IF NOT EXISTS fecha_nacimiento date,
  ADD COLUMN IF NOT EXISTS comuna text,
  ADD COLUMN IF NOT EXISTS grupo text,
  ADD COLUMN IF NOT EXISTS horario text;

-- Insertar plantel Asociación Buin 2026 (109 jugadores)

-- Ajustar sesiones_limite según días de entrenamiento (entrenamientos_por_semana × 4)
UPDATE jugadores
SET sesiones_limite = entrenamientos_por_semana * 4
WHERE club_id = 'ec1ef215-0ab5-43c6-abf4-fc5578b17bcc'
  AND entrenamientos_por_semana IS NOT NULL;
